Rule.Source:
import java.util.HashMap;
import sailpoint.api.Aggregator;
import sailpoint.api.SailPointContext;
import sailpoint.connector.Connector;
import sailpoint.connector.ConnectorException;
import sailpoint.object.Application;
import sailpoint.object.Attributes;
import sailpoint.object.ResourceObject;
import sailpoint.object.Rule;
import sailpoint.object.TaskResult;
import sailpoint.tools.GeneralException;
import sailpoint.tools.Util;
/*******************************************************************************************/
		/****IMP. NOTE: DO NOT USE THIS RULE TO EXECUTE Active Directory (AD) Single Aggregations.**/
		/*******************************************************************************************/
		String returnMessage = "";
		boolean correlationOnly = true;
		boolean exeAggregate = false;
		boolean isAuthoritative = false;
		String applicationName = ""; //Name of the application
		String accountName = ""; //This is the native Identity of the Application account


		Application appObject;
		try {
			appObject = context.getObjectByName(Application.class, applicationName);
		} catch (GeneralException e2) {
			returnMessage = "Failed to construct an instance of connector [" + applicationName + "] "+e2.getMessage();
			return returnMessage;
		}
		String appConnName = appObject.getConnector();
		Connector appConnector;
		try {
			appConnector = sailpoint.connector.ConnectorFactory.getConnector(appObject, null);
		} catch (GeneralException e1) {
			returnMessage = "Failed to construct an instance of connector [" + appConnName + "] "+e1.getMessage();
			return returnMessage;
			
		}
		String objType = appObject.getType().toString();
		isAuthoritative = appObject.isAuthoritative()
		if(isAuthoritative && !Util.nullSafeCaseInsensitiveEq("Active Directory - Direct",objType)){
			exeAggregate = true;
			
		} else if(Util.nullSafeCaseInsensitiveEq("Active Directory - Direct",objType)) {
			returnMessage = "You cannot execute this rule for any Active Directory Connector / Application";
			return returnMessage;
		}
		else{
			//correlationOnly = true;
			exeAggregate = true;
		}
		if (null == appConnector) {
		   returnMessage = "Failed to construct an instance of connector [" + appConnName + "]";
		   return returnMessage;
		}
		ResourceObject rObj = null;
		try {
		   rObj = (ResourceObject) appConnector.getObject("account", accountName, null);
		 } catch (sailpoint.connector.ObjectNotFoundException onfe) {
		   returnMessage = onfe.getMessage(); 
		   return returnMessage;
		} catch (ConnectorException e) {
			returnMessage = "Exception connecting to application: "+e.getMessage();
			return returnMessage;
		}
		if (null == rObj) {
		   returnMessage = "ERROR: Could not get ResourceObject for account: " + accountName;
		   return returnMessage;
		}

		Rule customizationRule = appObject.getCustomizationRule();
		if (null != customizationRule) {
		   try {
		      HashMap ruleArgs = new HashMap();
		      ruleArgs.put("context",context);
		      ruleArgs.put("object",rObj);
		      ruleArgs.put("application",appObject);
		      ruleArgs.put("connector",appConnector);
		      ruleArgs.put("state",new HashMap());
		      ResourceObject newRObj = (ResourceObject) context.runRule(customizationRule, ruleArgs, null);
		      if (null != newRObj) {
		         rObj = newRObj;
		         
		      }
		   } catch (Exception ex) {
		       returnMessage = "Error while running Customization rule for " + applicationName;
			   return returnMessage;
		   } 
		}
		Attributes argMap = new Attributes();
		//argMap.put("promoteAttributes","true");
		//argMap.put("correlateEntitlements","true");
		argMap.put("correlateOnly", correlationOnly);
		argMap.put("noOptimizeReaggregation","true");  // Note: Set to false to disable re-correlation.
		// Consturct an aggregator instance.
		if(exeAggregate) {
			Aggregator agg = new Aggregator(context, argMap);
			if (null == agg) {
			   returnMessage = "Null Aggregator returned from constructor.  Unable to Aggregate!";
			   return returnMessage;
			}
		
		// Invoke the aggregation task by calling the aggregate() method.
		// Note: the aggregate() call may take serveral seconds to complete.
		
			TaskResult taskResult;
			try {
				taskResult = agg.aggregate(appObject, rObj);
			} catch (GeneralException e) {
				returnMessage = "Exception getting task results: "+ e.getMessage();
				return returnMessage;
			}
			if (null == taskResult) {
			   returnMessage = "ERROR: Null taskResult returned from aggregate() call.";
			   return returnMessage;
			}
			
			returnMessage = "success";
		}else {
			returnMessage = "Single Aggregation could not be executed";
		}
		return returnMessage;
